class MedianFinder {
    double leftMedian, rightMedian;

    public MedianFinder() {
    }

    public void addNum(int num) {
        if (num < leftMedian) {
            if (leftMedian == 0) {
                leftMedian = num;
            } else {
                if (rightMedian == 0) {
                    if (num < leftMedian) {
                        leftMedian = num;
                    } else {
                        rightMedian = num;
                    }
            }
        }
    }

    public double findMedian() {
        if (leftMedian == 0 && rightMedian == 0) {
            return 0.0;
        } else if (leftMedian == 0) {
            return leftMedian;
        } else if (rightMedian == 0) {
            return rightMedian;
        } else {
            if (leftMedian > rightMedian) {
                double median = (leftMedian + rightMedian) / 2.0;
            } else {
                double median = leftMedian;
            }
            return median;
        }
    }
}
